fixed_code:
method SumOfNegativeNumbers(a: array<int>) returns (sum: int)
    requires a != null
    ensures sum == sumNegatives(a, a.Length)
{
    sum := 0;
    var i := 0;
    while i < a.Length
        invariant 0 <= i <= a.Length
        invariant sum == sumNegatives(a, i)
    {
        if a[i] < 0 {
            sum := sum + a[i];
        }
        i := i + 1;
    }
    assert sum == sumNegatives(a, a.Length);
}

function sumNegatives(a: array<int>, n: int): int
    requires 0 <= n <= a.Length
    requires a != null
    reads a
    decreases n
{
    if n == 0 then 0
    else if a[n - 1] < 0 then a[n - 1] + sumNegatives(a, n - 1)
    else sumNegatives(a, n - 1)
}
